def transform(a, invert):
    n = len(a)
    j = 0
    for i in range(1, n):
        bit = n >> 1
        while j & bit:
            j ^= bit
            bit >>= 1
        j ^= bit
        if i < j:
            a[i], a[j] = a[j], a[i]
    len_ = 2
    while len_ <= n:
        ang = 2 * math.pi / len_ * (-1 if invert else 1)
        wlen = complex(math.cos(ang), math.sin(ang))
        for i in range(0, n, len_):
            w = 1 + 0j
            for j in range(i, i + len_ // 2):
                u = a[j]
                v = a[j + len_ // 2] * w
                a[j] = u + v
                a[j + len_ // 2] = u - v
                w *= wlen
        len_ <<= 1
    if invert:
        for i in range(n):
            a[i] /= n

